Create a C++ program to print all the possible combinations of a four digit number.

### Response:
#include <iostream>
using namespace std;

// Function to calculate all the possible combinations of
// a four digit number
void printCombinations(int num)
{
 int nums[4];

 for (int i = 0; i < 4; i++) {
 nums[i] = (num >> (3 - i)) & 1;
 }

 for (int i = 0; i < (1 << 4); i++) {
 for (int j = 0; j < 4; j++) {
 if (i & (1 << j))
 cout << nums[j];
 }
 cout << endl;
 }
}

int main()
{
 int num;

 // Get the four digit number from the user
 cout << "Enter a four digit number: ";
 cin >> num;

 cout << "All possible combinations: \n";
 printCombinations(num);

 return 0;
}

