class TypeInferrer {

    public static String inferType(String input) {
        int number;
        boolean booleanValue;
        double doubleValue;

        try {
            number = Integer.parseInt(input);
            return "int";
        } catch(NumberFormatException e) {
            try {
                doubleValue = Double.parseDouble(input);
                return "double";
            } catch(NumberFormatException e2) {
                try {
                    booleanValue = Boolean.parseBoolean(input);
                    return "boolean";
                } catch(NumberFormatException e3) {
                    return "string";
                }
            }
        }
    }

}

### Instruction:
Design a program using Java that reads an integer from a user input and prints its digits in reverse.

### Response:
import java.util.Scanner;

public class ReverseDigits {
  public static void main(String[] args) {
    int number, reversedNumber = 0;
    Scanner scanner = new Scanner(System.in);

    System.out.println("Enter an integer: ");
    number = scanner.nextInt();

    // Reverse the digits
    while (number != 0) {
        reversedNumber = reversedNumber * 10 + number % 10;
        number = number / 10;
    }

    System.out.println("Reversed number: " + reversedNumber);
    scanner.close();
  }
}

