### Response:
def are_anagrams(string, strings_list):
    for i in range(len(strings_list)):
        for j in range(i + 1, len(strings_list)):
            ai = list(string)
            aj = list(strings_list[i])
            ak = list(strings_list[j])
            if sorted(ai) == sorted(aj) or sorted(ai) == sorted(ak):
                return True
    return False

