### Instruction:
Write a Java program to implement a queue using an array.

### Response:
public class Queue {

 private int[] arr;
 private int length;
 private int first;
 private int last;

 public Queue(int size) {
  arr = new int[size];
  length = 0;
  first = 0;
  last = -1;
 }

 public void enqueue(int n) {
  if (length == arr.length) {
   System.out.println("Queue is full!");
   return;
  }
  last = (last + 1) % arr.length;
  arr[last] = n;
  length++;
 }

 public int dequeue() {
  if (length == 0) {
   System.out.println("Queue is empty!");
   return -1;
  }
  int value = arr[first];
  arr[first] = 0;
  first = (first + 1) % arr.length;
  length--;
  return value;
 }
}

