Create a program in C++ to find the maximum subarray sum from a given array.

### Response:
#include <iostream>
#include <algorithm>

const int arrSize = 6;
int arr[arrSize] = {3, -1, 4, 5, -6, 7};

int maxSubArraySum() {
    int max_so_far = 0;
    int max_ending_here = 0;

    for (int i = 0; i < arrSize; i++) {
        max_ending_here += arr[i];
        if (max_ending_here < 0)
            max_ending_here = 0;
        else if (max_so_far < max_ending_here)
            max_so_far = max_ending_here;
    }
    return max_so_far;
}

int main() {
    int maxSum = maxSubArraySum();
    std::cout << "The maximum subarray sum is " << maxSum << std::endl;
    return 0;
}

// Output: The maximum subarray sum is 15

