### Instruction:
Update the React Native application created in task 5. This time users should be able to select more than one coffee cup at once.

### Response:
import React, { useState } from 'react';
import { StyleSheet, View, Text, Image, TouchableOpacity, Alert } from 'react-native';

const coffeeCups = [
 { id: 1, image: require('./images/coffee-cup-1.png') },
 { id: 2, image: require('./images/coffee-cup-2.png') },
 { id: 3, image: require('./images/coffee-cup-3.png') }
];

const App = () => {
 const [coffeeCount, setCoffeeCount] = useState(0);
 const [selectedCups, setSelectedCups] = useState([]);

 const addCoffee = () => {
 setCoffeeCount(coffeeCount + 1);
 };

 const selectCup = id => {
 const alreadySelected = selectedCups.find(cupId => cupId === id);
 if (alreadySelected) {
 Alert.alert(
 'Cannot select multiple cups',
 'You can only select one cup at a time',
 [{ text: 'OK', onPress: () => {} }],
 { cancelable: false }
 );
 return;
 }
 setSelectedCups([...selectedCups, id]);
 };

return (
 <View style={styles.container}>
 <Text style={styles.title}>Coffee Tracker</Text>

 <View style={styles.coffeeCounter}>
 <Text style={styles.coffeeCounterText}>{coffeeCount}</Text>
 </View>

 <View style={styles.coffeeCups}>
 {coffeeCups.map(cup => (
 <TouchableOpacity
 key={cup.id}
 style={[
 styles.coffeeCup,
 selectedCups.includes(cup.id) ? styles.coffeeCupSelected : {}
 ]}
 onPress={() => selectCup(cup.id)}
 >
 <Image
 source={cup.image}
 style={styles.coffeeCupImage}
 />
 </TouchableOpacity>
 ))}
 <TouchableOpacity
 style={styles.submitButton}
 onPress={addCoffee}
 >
 <Text style={styles.submitButtonText}>Submit</Text>
 </TouchableOpacity>
 </View>
 </View>
 );
};

const styles = StyleSheet.create({
 ...
 coffeeCupSelected: {
 opacity: 0.5
 },
 submitButton: {
 width: 80,
 height: 30,
 backgroundColor: '#282828',
 alignItems: 'center',
 justifyContent: 'center',
 margin: 10
 },
 submitButtonText: {
 fontSize: 16,
 fontWeight: '700',
 color: '#ffe25f'
 }
});

export default App;

